import React, { useState, useRef } from 'react';

const FoodDetectionApp = () => {
  const [currentImage, setCurrentImage] = useState(null);
  const [imageFile, setImageFile] = useState(null);
  const [detectionResults, setDetectionResults] = useState(null);
  const [ocrResults, setOcrResults] = useState('');
  const [geminiResults, setGeminiResults] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [processingStep, setProcessingStep] = useState('');
  const [confidence, setConfidence] = useState(0.5);
  const [statusMessage, setStatusMessage] = useState('준비 완료. 이미지를 로드하세요.');
  const [isDragOver, setIsDragOver] = useState(false);

  // 드래그 앤 드롭 핸들러
  const handleDragOver = (e) => {
    e.preventDefault();
    setIsDragOver(true);
  };

  const handleDragLeave = (e) => {
    e.preventDefault();
    setIsDragOver(false);
  };

  const handleDrop = (e) => {
    e.preventDefault();
    setIsDragOver(false);
    
    const files = e.dataTransfer.files;
    if (files.length > 0) {
      const file = files[0];
      if (file.type.startsWith('image/')) {
        console.log('드롭된 파일:', file.name);
        setImageFile(file);
        
        const reader = new FileReader();
        reader.onload = (e) => {
          setCurrentImage(e.target.result);
          setDetectionResults(null);
          setOcrResults('');
          setGeminiResults('');
          setStatusMessage(`이미지 로드 완료: ${file.name}`);
        };
        reader.readAsDataURL(file);
      } else {
        setStatusMessage('이미지 파일만 업로드 가능합니다.');
      }
    }
  };
  
  const fileInputRef = useRef(null);

  // 인라인 스타일 정의
  const styles = {
    buttonHover: {
      transition: 'all 0.3s ease',
      transform: 'translateY(-1px)',
      boxShadow: '0 4px 12px rgba(0, 0, 0, 0.15)'
    },
    customScrollbar: {
      scrollbarWidth: 'thin',
      scrollbarColor: '#c1c1c1 #f1f1f1'
    },
    rangeSlider: {
      WebkitAppearance: 'none',
      appearance: 'none',
      height: '6px',
      borderRadius: '3px',
      background: '#e5e7eb',
      outline: 'none'
    }
  };

  // 기본 아이콘 컴포넌트들
  const CameraIcon = () => (
    <span className="inline-block w-6 h-6 text-center text-blue-600">📷</span>
  );

  const UploadIcon = () => (
    <span className="inline-block w-4 h-4 text-center">📁</span>
  );

  const EyeIcon = () => (
    <span className="inline-block w-4 h-4 text-center">👁️</span>
  );

  const BrainIcon = () => (
    <span className="inline-block w-4 h-4 text-center">🧠</span>
  );

  const FileTextIcon = () => (
    <span className="inline-block w-4 h-4 text-center">📄</span>
  );

  const SettingsIcon = () => (
    <span className="inline-block w-4 h-4 text-center">⚙️</span>
  );

  const LoadingSpinner = () => (
    <div className="animate-spin rounded-full h-4 w-4 sm:h-5 sm:w-5 border-b-2 border-blue-600"></div>
  );

  // 이미지 로드 함수
  const handleImageLoad = (event) => {
    const file = event.target.files[0];
    if (file) {
      console.log('파일 선택됨:', file.name, file.type, file.size);
      setImageFile(file);
      
      // 이미지 파일 형식 체크
      if (!file.type.startsWith('image/')) {
        setStatusMessage('이미지 파일만 업로드 가능합니다.');
        return;
      }
      
      const reader = new FileReader();
      reader.onload = (e) => {
        console.log('이미지 로드 완료');
        setCurrentImage(e.target.result);
        setDetectionResults(null);
        setOcrResults('');
        setGeminiResults('');
        setStatusMessage(`이미지 로드 완료: ${file.name}`);
      };
      reader.onerror = (e) => {
        console.error('이미지 로드 실패:', e);
        setStatusMessage('이미지 로드 실패');
      };
      reader.readAsDataURL(file);
    } else {
      console.log('파일이 선택되지 않음');
    }
  };

  // YOLO 탐지 실행
  const runDetection = async () => {
    if (!imageFile) {
      setStatusMessage('먼저 이미지를 로드하세요.');
      return;
    }

    setIsProcessing(true);
    setProcessingStep('식품 탐지 중...');
    setStatusMessage('식품 탐지 중...');

    try {
      const formData = new FormData();
      formData.append('file', imageFile);
      formData.append('confidence', confidence);

      const response = await fetch('http://127.0.0.1:8000/detect', {
        method: 'POST',
        body: formData,
      });

      if (response.ok) {
        const result = await response.json();
        setDetectionResults(result);
        setStatusMessage(`식품 탐지 완료: ${result.detections?.length || 0}개 객체 발견`);
      } else {
        throw new Error('탐지 API 호출 실패');
      }
    } catch (error) {
      setStatusMessage(`식품 탐지 오류: ${error.message}`);
      console.error('Detection error:', error);
    } finally {
      setIsProcessing(false);
      setProcessingStep('');
    }
  };

  // OCR 및 Gemini 분석 실행
  const runOcrAnalysis = async () => {
    if (!imageFile) {
      setStatusMessage('먼저 이미지를 로드하세요.');
      return;
    }

    setIsProcessing(true);
    setProcessingStep('OCR 텍스트 추출 중...');
    setStatusMessage('OCR 텍스트 추출 중...');

    try {
      const formData = new FormData();
      formData.append('file', imageFile);

      // OCR 실행
      const ocrResponse = await fetch('http://127.0.0.1:8000/ocr', {
        method: 'POST',
        body: formData,
      });

      if (ocrResponse.ok) {
        const ocrResult = await ocrResponse.json();
        setOcrResults(ocrResult.text || '추출된 텍스트가 없습니다.');
        
        if (ocrResult.text) {
          setProcessingStep('Gemini로 텍스트 분석 중...');
          setStatusMessage('Gemini로 텍스트 분석 중...');

          // Gemini 분석 실행
          const geminiResponse = await fetch('http://127.0.0.1:8000/analyze', {
            method: 'POST',
            headers: {
              'Content-Type': 'application/json',
            },
            body: JSON.stringify({
              text: ocrResult.text,
              detection_results: detectionResults
            }),
          });

          if (geminiResponse.ok) {
            const geminiResult = await geminiResponse.json();
            setGeminiResults(geminiResult.analysis || '분석 결과가 없습니다.');
            setStatusMessage('OCR 및 텍스트 분석 완료');
          } else {
            setGeminiResults('텍스트 분석 실패');
            setStatusMessage('OCR 완료, 텍스트 분석 실패');
          }
        } else {
          setStatusMessage('OCR 텍스트 추출 실패');
        }
      } else {
        throw new Error('OCR API 호출 실패');
      }
    } catch (error) {
      setStatusMessage(`OCR 또는 텍스트 분석 오류: ${error.message}`);
      console.error('OCR/Analysis error:', error);
    } finally {
      setIsProcessing(false);
      setProcessingStep('');
    }
  };

  return (
    <div className="min-h-screen bg-gray-50">
      <div className="w-full max-w-6xl mx-auto p-2 sm:p-4">
        {/* 헤더 - 모바일 최적화 */}
        <div className="bg-white rounded-lg shadow-md p-3 sm:p-6 mb-3 sm:mb-6">
          <h1 className="text-xl sm:text-3xl font-bold text-gray-800 mb-2 flex items-center gap-2 sm:gap-3">
            <CameraIcon />
            <span className="truncate">식품 이미지 분석</span>
          </h1>
          <p className="text-xs sm:text-base text-gray-600 hidden sm:block">
            YOLO 객체 탐지, OCR 텍스트 추출, Gemini AI 분석을 지원합니다
          </p>
        </div>

        {/* 컨트롤 패널 - 모바일 우선 */}
        <div className="bg-white rounded-lg shadow-md p-3 sm:p-6 mb-3 sm:mb-6">
          <div className="flex flex-col sm:flex-row gap-2 sm:gap-4 mb-3 sm:mb-4">
            <input
              type="file"
              accept="image/*,.jpg,.jpeg,.png,.bmp,.gif,.webp"
              onChange={handleImageLoad}
              ref={fileInputRef}
              className="hidden"
              multiple={false}
            />
            
            <button
              onClick={() => {
                console.log('이미지 로드 버튼 클릭');
                fileInputRef.current?.click();
              }}
              className="flex items-center justify-center gap-2 px-3 py-2 sm:px-4 sm:py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-all duration-300 hover:shadow-lg hover:-translate-y-0.5 text-sm sm:text-base"
              style={{ minHeight: '44px', minWidth: '44px' }}
            >
              <UploadIcon />
              이미지 로드
            </button>

            <button
              onClick={runDetection}
              disabled={!currentImage || isProcessing}
              className="flex items-center justify-center gap-2 px-3 py-2 sm:px-4 sm:py-2 bg-green-600 text-white rounded-lg hover:bg-green-700 disabled:bg-gray-400 disabled:cursor-not-allowed transition-all duration-300 hover:shadow-lg hover:-translate-y-0.5 text-sm sm:text-base"
              style={{ minHeight: '44px', minWidth: '44px' }}
            >
              <EyeIcon />
              식품 탐지
            </button>

            <button
              onClick={runOcrAnalysis}
              disabled={!currentImage || isProcessing}
              className="flex items-center justify-center gap-2 px-3 py-2 sm:px-4 sm:py-2 bg-purple-600 text-white rounded-lg hover:bg-purple-700 disabled:bg-gray-400 disabled:cursor-not-allowed transition-all duration-300 hover:shadow-lg hover:-translate-y-0.5 text-sm sm:text-base"
              style={{ minHeight: '44px', minWidth: '44px' }}
            >
              <BrainIcon />
              OCR 및 분석
            </button>
          </div>

          {/* 신뢰도 설정 - 모바일 최적화 */}
          <div className="flex items-center gap-2 sm:gap-4">
            <label className="text-xs sm:text-sm font-medium text-gray-700 flex items-center gap-1 sm:gap-2 whitespace-nowrap">
              <SettingsIcon />
              신뢰도:
            </label>
            <input
              type="range"
              min="0.1"
              max="0.9"
              step="0.1"
              value={confidence}
              onChange={(e) => setConfidence(parseFloat(e.target.value))}
              className="flex-1"
            />
            <span className="text-xs sm:text-sm font-medium text-gray-600 min-w-[2rem]">
              {confidence.toFixed(1)}
            </span>
          </div>
        </div>

        {/* 메인 콘텐츠 - 모바일에서는 세로 배치, 데스크톱에서는 가로 배치 */}
        <div className="flex flex-col lg:flex-row gap-3 sm:gap-6">
          {/* 이미지 표시 영역 */}
          <div className="flex-1 lg:flex-[2]">
            <div className="bg-white rounded-lg shadow-md p-3 sm:p-6">
              <div 
                className={`border-2 border-dashed rounded-lg min-h-[250px] sm:min-h-[400px] flex items-center justify-center transition-all duration-300 cursor-pointer ${
                  isDragOver 
                    ? 'border-blue-500 bg-blue-50' 
                    : 'border-gray-300 hover:border-blue-400 hover:bg-blue-50'
                }`}
                onDragOver={handleDragOver}
                onDragLeave={handleDragLeave}
                onDrop={handleDrop}
                onClick={() => {
                  console.log('이미지 영역 클릭');
                  fileInputRef.current?.click();
                }}
              >
                {currentImage ? (
                  <img
                    src={currentImage}
                    alt="Uploaded"
                    className="max-w-full max-h-[300px] sm:max-h-[600px] rounded-lg shadow-sm object-contain transition-transform duration-300 hover:scale-105"
                    onClick={(e) => e.stopPropagation()}
                  />
                ) : (
                  <div className="text-center text-gray-500 p-4">
                    <div className="text-5xl sm:text-7xl mb-3">📷</div>
                    <p className="text-sm sm:text-lg font-medium">
                      {isDragOver ? '파일을 놓아주세요' : '이미지를 업로드하세요'}
                    </p>
                    <p className="text-xs sm:text-sm mt-1">
                      {isDragOver ? '' : 'JPG, PNG, BMP 파일 지원 (클릭 또는 드래그)'}
                    </p>
                  </div>
                )}
              </div>
            </div>

            {/* 진행 상태 - 이미지 아래 */}
            {isProcessing && (
              <div className="bg-blue-50 border border-blue-200 rounded-lg p-3 sm:p-4 mt-3 sm:mt-4">
                <div className="flex items-center gap-2 sm:gap-3">
                  <LoadingSpinner />
                  <span className="text-blue-800 font-medium text-sm sm:text-base">{processingStep}</span>
                </div>
              </div>
            )}
          </div>

          {/* 결과 표시 영역 */}
          <div className="flex-1 space-y-3 sm:space-y-6">
            {/* 탐지 결과 */}
            <div className="bg-white rounded-lg shadow-lg p-3 sm:p-6 hover:shadow-xl transition-shadow duration-300">
              <h3 className="text-base sm:text-lg font-semibold text-gray-800 mb-3 sm:mb-4 flex items-center gap-1 sm:gap-2">
                <EyeIcon />
                식품 탐지 결과
              </h3>
              <div className="bg-gray-50 rounded-lg p-3 sm:p-4 min-h-[120px] max-h-[150px] sm:max-h-[200px] overflow-y-auto" style={styles.customScrollbar}>
                {detectionResults ? (
                  <div className="space-y-1 sm:space-y-2">
                    {detectionResults.detections?.map((detection, index) => (
                      <div key={index} className="text-xs sm:text-sm p-2 rounded hover:bg-blue-50 transition-colors duration-200">
                        <span className="font-medium">{index + 1}.</span>{' '}
                        <span className="text-blue-600 font-semibold">{detection.class}</span>
                        {detection.original_class && detection.class === 'other' && (
                          <span className="text-gray-500"> (원본: {detection.original_class})</span>
                        )}
                        <span 
                          className={`ml-2 font-semibold ${
                            detection.confidence > 0.7 ? 'text-green-600' : 
                            detection.confidence > 0.4 ? 'text-orange-500' : 'text-red-500'
                          }`}
                        >
                          ({(detection.confidence * 100).toFixed(1)}%)
                        </span>
                      </div>
                    )) || <p className="text-gray-500 text-xs sm:text-sm">탐지된 객체가 없습니다.</p>}
                  </div>
                ) : (
                  <p className="text-gray-500 text-xs sm:text-sm">탐지 결과가 없습니다.</p>
                )}
              </div>
            </div>

            {/* OCR 결과 */}
            <div className="bg-white rounded-lg shadow-lg p-3 sm:p-6 hover:shadow-xl transition-shadow duration-300">
              <h3 className="text-base sm:text-lg font-semibold text-gray-800 mb-3 sm:mb-4 flex items-center gap-1 sm:gap-2">
                <FileTextIcon />
                OCR 텍스트
              </h3>
              <div className="bg-gray-50 rounded-lg p-3 sm:p-4 min-h-[120px] max-h-[150px] sm:max-h-[200px] overflow-y-auto" style={styles.customScrollbar}>
                <p className="text-xs sm:text-sm text-gray-700 whitespace-pre-wrap break-words leading-relaxed">
                  {ocrResults || '추출된 텍스트가 없습니다.'}
                </p>
              </div>
            </div>

            {/* Gemini 분석 결과 */}
            <div className="bg-white rounded-lg shadow-lg p-3 sm:p-6 hover:shadow-xl transition-shadow duration-300">
              <h3 className="text-base sm:text-lg font-semibold text-gray-800 mb-3 sm:mb-4 flex items-center gap-1 sm:gap-2">
                <BrainIcon />
                Gemini 분석 결과
              </h3>
              <div className="bg-gray-50 rounded-lg p-3 sm:p-4 min-h-[120px] max-h-[150px] sm:max-h-[200px] overflow-y-auto" style={styles.customScrollbar}>
                <p className="text-xs sm:text-sm text-gray-700 whitespace-pre-wrap break-words leading-relaxed">
                  {geminiResults || '분석 결과가 없습니다.'}
                </p>
              </div>
            </div>
          </div>
        </div>

        {/* 상태바 - 하단 고정 */}
        <div className="mt-3 sm:mt-6 bg-white rounded-lg shadow-md p-3 sm:p-4">
          <div className="flex items-center gap-2">
            <div className="w-2 h-2 bg-green-500 rounded-full flex-shrink-0"></div>
            <span className="text-xs sm:text-sm text-gray-700 truncate">{statusMessage}</span>
          </div>
        </div>
      </div>
